module lfsr(CLK, RST, LFSR_OUT);
input CLK, RST;
output [4:0] LFSR_OUT;
reg [4:0] LFSR_OUT;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge RST or posedge dbg_halt) begin
    if (RST)
        LFSR_OUT <= 5'b00001; // Non-zero initial value
    else begin
        LFSR_OUT <= {LFSR_OUT[3:0], LFSR_OUT[4] ^ LFSR_OUT[2]};
    end
end

endmodule
